"""
MKT Context — Luke chapters 2–3
Output: data/commentary/mkt-context/luke.json
Run: python3 scripts/zc-context-luke-2-3.py

Context layer: Second Temple Jewish background, Roman occupation, honor-shame
dynamics, what the original audience already knew and assumed.

Key nodes:
- 2:1: Roman census machinery; Caesar Augustus's divine titles
- 2:7: Manger setting — animal stalls, the katalyma problem, and social shame
- 2:8: Shepherds' low status in Jewish society vs. their Davidic associations
- 2:11: The three titles — Savior/Christ/Lord — in Roman and Jewish context
- 2:14: Pax Romana vs. eschatological peace; eudokias genitive crux
- 2:21-24: Torah observance: circumcision, purification, firstborn redemption
- 2:24: Two doves = offering of the poor (Lev 12:8) — a poverty signal
- 2:25: "Consolation of Israel" — the Second Temple waiting posture
- 2:32: Isaiah's light-to-Gentiles universalism; Jewish-Gentile inclusion tension
- 2:41-43: Passover pilgrimage from Galilee — the annual caravan culture
- 2:46: Temple learning environment — sit-and-debate with teachers
- 3:1: The synchronism formula — Greco-Roman historiographical dating convention
- 3:1: Political landscape of Judea and surrounding territories ca. 28 CE
- 3:2: Dual high priesthood — Annas/Caiaphas political history
- 3:3: John's baptism vs. Jewish mikveh; wilderness location significance
- 3:8: Ethnic confidence in Abrahamic descent — Second Temple identity
- 3:15: Multiple messianic expectations in Second Temple Judaism
- 3:19: Herod Antipas + Herodias — the Herodian dynasty's internal politics
- 3:23-38: Lukan genealogy's distinctive features (Adam, Nathan line, Cainan)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH2_3 = {
  "2": {
    "1": '<p>Caesar Augustus (63 BCE–14 CE) ruled the Roman world as its first emperor from 27 BCE. His reign transformed the Mediterranean from a republic into an autocracy while maintaining republican forms. The periodic <strong>census</strong> (Latin <em>census</em>; Greek <em>apographē</em> = registration) served two Roman purposes: tax assessment and military conscription eligibility. For subject peoples like Judeans, it was a constant reminder of imperial domination. Augustus also accumulated divine titles — <em>divi filius</em> (son of the divine [Julius Caesar]), <em>soter</em> (savior), <em>kyrios</em> (lord), bearer of a "gospel" (<em>euangelion</em>) that his birth was for the world — titles that Luke\'s infancy narrative systematically applies to Jesus instead. The audience familiar with imperial cult language would have felt the competition immediately.</p>',
    "2": '<p>The historical identification of this census with Quirinius\'s governorship of Syria presents a well-known chronological difficulty: Quirinius is known from Josephus (<em>Antiquities</em> 18.1-2) to have conducted a census of Judea in 6–7 CE, roughly ten years after Herod the Great\'s death (4 BCE) when Jesus was born. Ancient solutions include: (1) a previous, earlier Quirinius governorship during Herod\'s time; (2) Luke using <em>prōtē</em> (first) to mean "before" — "this registration was before the Quirinius census"; (3) a different "Quirinius." The text stands as a chronological marker that Luke\'s original audience may have understood differently than modern readers. The point is not precision but anchoring the birth in Roman imperial history.</p>',
    "3": '<p>The Roman registration system in the eastern provinces did sometimes require registration in ancestral localities, particularly for property and census records. Egyptian papyri from the early second century CE document similar return-to-origin registration requirements. The journey from Nazareth to Bethlehem (approximately 130 km on foot through the hill country) would have taken 3-5 days. Joseph\'s Davidic lineage makes Bethlehem the ancestral registration point: Bethlehem is the town of Jesse and David (1 Sam 16:1; 17:12; 20:6). Luke\'s original audience, familiar with Roman administrative requirements, would have found the return-to-origin requirement plausible.</p>',
    "4": '<p>Nazareth in Galilee was a small village — no archaeological evidence before the first century BCE; not mentioned in the Hebrew Bible, Josephus\'s <em>Jewish War</em>, or the Mishnah. Its insignificance is implied in John 1:46 ("Can anything good come from Nazareth?"). Bethlehem, by contrast, carried enormous theological weight as the birthplace of David and the prophesied birthplace of the Davidic Messiah (Mic 5:2). Joseph\'s belonging to "the house and line of David" (<em>ex oikou kai patrias Dauid</em>) is the Davidic genealogical credential that legitimizes the Messianic claim. First-century Jews in Judea maintained detailed tribal and family records; Josephus notes that priests especially preserved genealogical documents (<em>Against Apion</em> 1.7).</p>',
    "5": '<p>Mary\'s status as "pledged to be married" (<em>emnēsteumenē</em>) placed her in the second stage of Jewish marriage: the betrothal period (<em>erusin</em> or <em>kiddushin</em>) during which the couple was legally bound but had not yet moved in together (<em>nissu\'in</em> = the home-taking completion). A betrothed woman was legally "wife" for purposes of adultery law (Deut 22:23-24) but physically still in her parents\' home. An unmarried pregnant woman in this period would face severe social stigma; the Mishnah (<em>Ketubot</em> 1.5) discusses the legal status of betrothed women whose betrothal is complicated by pregnancy. Joseph\'s decision to take Mary with him signals his acceptance of the situation.</p>',
    "6": '<p>Luke\'s "while they were there, the time came" (<em>en tō einai autous ekei eplēsthēsan hai hēmerai tou tekein autēn</em>) implies they had been in Bethlehem for some time before the birth, not that she gave birth the night they arrived. The fulfillment language (<em>eplēsthēsan</em> = the days were filled/completed) echoes LXX birth-narrative language (Gen 25:24; 29:21). The birth itself is narrated with extraordinary brevity; ancient historical biographies (including Plutarch\'s <em>Lives</em> and Suetonius\'s <em>Lives of the Twelve Caesars</em>) typically treated the circumstances of birth as highly significant, making Luke\'s brevity noteworthy.</p>',
    "7": '<p>The <em>katalyma</em> (guest room) problem has generated extensive debate: is it an "inn" (commercial lodging) or a "guest room" (in a private house)? The same word appears at 22:11 for the upper room of the Last Supper, clearly a private domestic room. If it means "guest room," the implication is that the family guest room was already full (with relatives), and the couple was directed to the lower level of the house or a cave-stable where animals were kept overnight. Palestinian houses in Bethlehem often had animal stalls on the ground level with family quarters above. A <em>phatnē</em> (manger = feeding trough) would be a permanent stone or wood trough built into the wall or floor of such a room. <em>Spargana</em> (swaddling cloths) were the standard birth-care practice — wrapping a newborn tightly was believed to strengthen limbs and provide warmth.</p>',
    "8": '<p>Shepherds (<em>poimenes</em>) held a complex social position in first-century Jewish Palestine. Economically necessary and biblically celebrated (David was a shepherd; Israel was YHWH\'s flock), shepherds were simultaneously regarded with social suspicion: their constant movement across others\' land made them likely to allow their flocks to graze on others\' crops (a form of theft). Rabbinic literature (m. <em>Sanhedrin</em> 3.3; b. <em>Sanhedrin</em> 25b) classified certain categories of shepherds as legally unreliable witnesses, disqualified from court testimony. The irony of the announcement going to socially marginal shepherds — rather than the priestly establishment in Jerusalem — is a key Lukan inversion. The "field-shepherds" (<em>poimenes agrauontes</em>) staying overnight in the fields place the scene in the lambing season, when round-the-clock supervision was required.</p>',
    "9": '<p>The <em>doxa Kyriou</em> (glory of the Lord) that "shone around" (<em>perielampsen</em>) the shepherds is the <em>shekinah</em> — the luminous divine presence that filled the tabernacle (Exod 40:34-35; Num 9:15-16) and the temple (1 Kgs 8:10-11; Ezek 43:4-5). The appearance of the angelic messenger with the divine glory light is the form of theophany familiar from LXX accounts of divine visitation (Dan 10:5-6; 1 Enoch 14:8-23). The shepherds\' fear (<em>ephobēthēsan phobon megan</em> = feared with great fear) follows the standard theophany pattern: vision of divine glory → overwhelming fear → angelic reassurance.</p>',
    "10": '<p>The angel\'s announcement begins with <em>euangelizō</em> (proclaim good news — the gospel-proclamation verb, used throughout Luke-Acts for the kingdom announcement). In the Roman imperial context, the birth of an emperor was announced as <em>euangelion</em> (good news): the Priene inscription (9 BCE) declared Augustus\'s birth to be "the beginning of good news for the world" (<em>ēn de archē tou kosmou tōn di auton euangeliōn</em>). Luke\'s angel uses the same vocabulary for the birth of Jesus, presenting a direct counter-claim to imperial ideology. <em>Panti tō laō</em> (for all the people — not just shepherds, not just Israel, but the fullness of the covenant people and ultimately all peoples).</p>',
    "11": '<p>Three titles are stacked: <em>Sōtēr</em> (Savior), <em>Christos</em> (Anointed/Messiah), <em>Kyrios</em> (Lord). <strong>Sōtēr</strong>: Caesar Augustus, Pompey, and various Hellenistic kings bore this title; it meant one who rescued, delivered, and preserved life. In Jewish usage it applied to YHWH as deliverer (Isa 43:3, 11; 45:21; Ps 27:1). <strong>Christos</strong>: the Greek translation of Hebrew <em>māšîaḥ</em> (anointed); in Second Temple Judaism there were multiple messianic expectations — a Davidic king-warrior (Psalms of Solomon 17-18), a priestly messiah (Community Rule from Qumran), a prophet-like-Moses (Deut 18:15). <strong>Kyrios</strong>: the LXX\'s standard translation of the divine name YHWH; applied to Jesus, it carries the full weight of the divine name. All three together constitute an implicit claim that exceeds any human ruler.</p>',
    "12": '<p>The sign (<em>sēmeion</em>) given to the shepherds is paradoxical: the Messiah will be found in a feeding trough, wrapped in strips of cloth. Signs in biblical usage are not proofs but distinguishing marks that allow recognition of a divinely-sent reality; the specific combination (<em>brephos esparganōmenon kai keimenon en phatnē</em> = a baby wrapped in cloths lying in a manger) is the identifier. The paradox is that the sign points to lowliness — the exact opposite of what Jewish messianic expectations typically envisioned. The audience expecting a warrior-king would be required to recognize the Messiah in this unexpected location.</p>',
    "13": '<p>The <em>stratia ouranios</em> (heavenly host/army — <em>stratia</em> = army, military force; "heavenly armies") is the angelic military assembly of divine warriors found throughout the OT (1 Kgs 22:19; Isa 6:1-3; Ps 103:21; 148:2; Dan 7:10). The <em>plethos</em> (great multitude) implies a vast assembly, not a small group. That this angelic army appears not at a military victory but at a birth in a stable — and sings of peace rather than announcing battle — is a cosmic inversion. The audience familiar with divine warrior language in the Psalms and Prophets would feel the redirection: the heavenly army is deployed for this.</p>',
    "14": '<p>The Gloria (<em>Doxa en hypsistois theō kai epi gēs eirēnē en anthrōpois eudokias</em>) engages the Roman ideology of <em>pax Romana</em> (Roman peace). Augustus had closed the Temple of Janus (indicating peace) and promoted himself as the bringer of universal peace; the <em>Ara Pacis Augustae</em> (Altar of Augustan Peace, 13-9 BCE) celebrated this explicitly. Luke\'s heavenly army declares a different peace — not the peace of military conquest but the peace that comes from the arrival of God\'s favor (<em>eudokia</em> = good pleasure, favorable disposition). The genitive <em>eudokias</em> (of his good pleasure) identifies the recipients as those on whom divine favor rests — a covenantal category rather than a political one.</p>',
    "15": '<p>The shepherds\' immediate response (<em>dielthōmen dē... kai idōmen</em> = let us go and see) models the appropriate response to divine announcement: not skepticism but prompt investigation. The phrase <em>to rēma touto to gegonos</em> (this word/thing that has happened) uses <em>rēma</em> in its Hebraic double sense: "word" (the announcement) and "thing" (the event announced, as in Hebrew <em>dābār</em>). The shepherds treat the angelic announcement and the birth-event as two aspects of the same divine <em>rēma</em>. Their going to Bethlehem to verify what the Lord had made known to them models the relationship between divine speech and historical event.</p>',
    "16": '<p>The shepherds "hurried off" (<em>ēlthan speusantes</em> = came hurrying) — <em>speudō</em> (hurry, make haste) appears at 19:5-6 for Zacchaeus\'s urgent descent; and 2:16 for Mary visiting Elizabeth. The urgency is appropriate to the announcement. The finding of Mary, Joseph, and the baby "lying in the manger" fulfills the sign exactly as given (v.12); the correspondence between sign and reality is the narrative validation of the angelic message. Luke names the three together — Mary first (she bore the child), then Joseph, then "the baby" — in a way that places the child as the climax of the discovery.</p>',
    "17": '<p>The shepherds "made known" (<em>egnōrisan</em> = made known, reported — the same verb as v.15\'s making known) the word spoken to them about the child. This reporting to "all who heard" (<em>pasi tois akousasin</em>) functions as the first human proclamation of the gospel. The shepherds — who were disqualified as witnesses in rabbinic law — become the first witnesses to the birth of the Messiah. Luke\'s irony is pointed: those excluded from legal testimony are the first authorized witnesses of the incarnation. Their announcement goes to "all who heard" in Bethlehem, not to the religious establishment in Jerusalem.</p>',
    "18": '<p>All who heard the shepherds\' report "were amazed" (<em>ethaumasan</em> = marveled, were astonished — the standard human response to the divine in Luke; also 1:21, 63; 2:18, 33; 4:22; 8:25; 9:43; 11:14; 20:26; 24:12, 41). Amazement in ancient Mediterranean culture was the appropriate response to the numinous and the unexpected; it signals that the hearers recognized they were in the presence of something exceeding ordinary categories. The amazement is not yet faith — it precedes the full understanding that Luke will develop through the Gospel.</p>',
    "19": '<p>Mary\'s response (<em>sunētērei panta ta rēmata tauta symballousa en tē kardia autēs</em> = treasuring all these words/things and pondering them in her heart) reflects the ancient practice of meditating on received divine communication to discern its meaning. <em>Symballousa</em> (pondering, comparing — from <em>symballō</em> = throw together) is a deliberative word: she is not merely memorizing but comparing, weighing, cross-referencing what the shepherds said against what she already knew from the annunciation, Elizabeth\'s greeting, and Zechariah\'s song. This verse is one of Luke\'s indicators that he had access to Mary\'s own perspective (1:26-38; 2:19, 51); some scholars suggest Mary herself was a source for the infancy narrative.</p>',
    "20": '<p>The shepherds\' return "glorifying and praising God" (<em>doxazontes kai ainountes ton theon</em>) closes the birth narrative with a doxological frame. <em>Doxazō</em> and <em>aineō</em> (glorify and praise) are the standard liturgical response to divine action throughout Luke-Acts (2:20; 5:25-26; 7:16; 13:13; 17:15; 18:43; 19:37; Acts 3:8; 4:21). The shepherds return to their regular work — they "returned" (<em>hypestrepsan</em>) to the fields — but the doxological frame transforms them: they are the same people doing the same work, but now as those who have seen the Messiah. This is Luke\'s model for discipleship within ordinary life.</p>',
    "21": '<p>Circumcision on the eighth day (Gen 17:12; Lev 12:3) was the covenantal sign marking male entry into the Abrahamic covenant. It was one of the most carefully observed commandments in Second Temple Judaism; even when other Torah observances were compromised (under Antiochus IV\'s forced hellenization), circumcision was the line many Jews died rather than cross (1 Macc 1:60-61; 2:46). The naming at circumcision was the normal practice: the child received his covenant identity and personal name at the same moment. Luke\'s note that the name "Jesus" was given by the angel before conception (1:31) emphasizes that the child\'s identity was determined from before birth — a divine initiative, not a human one.</p>',
    "22": '<p>The "purification rites required by the Law of Moses" (Lev 12:1-8) required a mother to present herself at the temple forty days after the birth of a male child (eighty days for a female) for ritual purification after childbirth. The presentation of the firstborn (<em>prōtotokos</em>) to the Lord (Exod 13:2, 12-15; Num 18:15-16) required "redeeming" the firstborn with a five-shekel payment. Luke combines both rituals in one Jerusalem visit. The mention of both rites signals the family\'s scrupulous Torah observance — a pattern Luke establishes clearly: Jesus was born into a Torah-keeping family that fulfilled every legal obligation.</p>',
    "23": '<p>The citation of Exod 13:2 ("Every male who opens the womb shall be called holy to the Lord") refers to the firstborn-redemption law rooted in the Exodus. Every firstborn male was in a sense "consecrated" (<em>hagion</em> = holy, set apart) to the Lord because YHWH spared the Israelite firstborns when he struck the Egyptian firstborns (Exod 12:23, 29-30). The firstborn\'s consecration was then "redeemed" (bought back) from temple service by the five-shekel payment — a reminder that Israel\'s firstborns "belonged" to YHWH by right. Luke\'s citation connects Jesus\'s presentation to the Exodus narrative: he is both firstborn and the fulfillment that redeems all others.</p>',
    "24": '<p>The offering of "a pair of doves or two young pigeons" (Lev 12:8) was the prescribed substitute for the normal lamb offering when the family could not afford it: "If she cannot afford a lamb, she is to bring two doves or two young pigeons" (Lev 12:8). This is explicitly the offering of poverty. Luke\'s inclusion of this detail serves as a subtle social marker: the family of the Messiah of Israel is poor. They cannot afford the standard purification offering. This detail anticipates the social location of Jesus\'s ministry among the poor (4:18; 6:20; 7:22) and the economic theme of Luke\'s Gospel more broadly. The audience reading or hearing this would recognize the two-bird offering as the marker of material poverty.</p>',
    "25": '<p>Simeon (<em>Symeōn</em>) is presented as a representative figure of faithful Second Temple Judaism: <em>dikaios kai eulabēs</em> (righteous and devout — the two halves of Jewish piety: legal righteousness and personal reverential devotion) and <em>prosdechomenos paraklēsin tou Israēl</em> (waiting for the consolation of Israel). The "consolation of Israel" (<em>paraklēsis tou Israēl</em>) is the technical phrase for the messianic comfort of Isaiah 40-66: "Comfort, comfort my people" (Isa 40:1). This waiting posture — patient, Spirit-led expectation — characterized a segment of Second Temple Judaism that believed the prophetic promises were about to be fulfilled. Qumran also exhibited this expectant posture. The Holy Spirit\'s presence on Simeon (v.25, 26, 27) marks him as a prophetically-gifted figure in the line of OT prophets.</p>',
    "26": '<p>The divine disclosure to Simeon that he would not die before seeing the Lord\'s Anointed (<em>ton Christon Kyriou</em> = the Anointed of the Lord — the messianic figure; also the LXX phrase for the king, Ps 2:2; Lam 4:20) reflects the prophetic pattern of personal divine communication: YHWH speaks directly to his servants, granting them specific knowledge about the timing of divine action. Simeon is portrayed as a man whose entire remaining life is oriented toward this single promised encounter; the promise has become the organizing center of his existence. The phrase "he would not die" (<em>mē idein thanaton</em>) echoes the promise to those who "will not taste death" in eschatological sayings (Luke 9:27).</p>',
    "27": '<p>The Spirit\'s movement (<em>en tō pneumati</em> = in the Spirit, moved by the Spirit) as the impetus for Simeon\'s entry into the temple courts at precisely the moment of the presentation reflects the divine orchestration that runs through Luke\'s infancy narrative. The temple courts (the <em>hieron</em> = the entire temple precinct, including the Court of Women and the Court of the Gentiles) are the setting; the inner <em>naos</em> (shrine building) would have been accessible only to priests. The "custom of the Law" (<em>to eithismenon tou nomou</em> = what was customary of the Law) refers to the combined presentation/purification rituals of vv.22-24.</p>',
    "28": '<p>Simeon "took the child in his arms" (<em>edexato auto eis tas agkalas autou</em> = received him into his arms) — the physical embrace of the infant Messiah by the waiting elderly prophet is one of the most emotionally resonant scenes in Luke\'s infancy narrative. The embrace is not merely affectionate but enacted recognition: Simeon receives the child into himself as the fulfillment of the promise he has been carrying. His immediate blessing of God (<em>eulogēsen ton theon</em>) is the doxological response to fulfilled expectation — the pattern throughout Luke where divine action is met with praise.</p>',
    "29": '<p>The Nunc Dimittis ("Now dismiss your servant in peace" — <em>nyn apolyeis ton doulon sou, Despota, kat eirēnēs</em>) is structured as a dismissal: a servant requests release from duty when the assigned task is complete. Simeon addresses God as <em>Despota</em> (Sovereign Master — from <em>despotēs</em> = absolute owner/master; used for God in Acts 4:24; Rev 6:10; and for Jesus\'s authority in 2 Pet 2:1; Jude 4) — the term of absolute authority. The servant who has served his master faithfully and completed his task asks to be released (<em>apolyeis</em> = you dismiss, release). "In peace" (<em>kat eirēnēs</em>) echoes the priestly benediction of Num 6:26 and anticipates the Gospel\'s peace-theme.</p>',
    "30": '<p>The ground of the dismissal request: "for my eyes have seen your salvation" (<em>hoti eidon hoi ophthalmoi mou to sōtērion sou</em>). <em>To sōtērion</em> (the salvation — from <em>sōtēr</em> = savior; the LXX uses <em>sōtērion</em> for YHWH\'s saving acts, as in Ps 50:23 LXX; Isa 40:5; 52:10) is what Simeon has now seen embodied in the infant. The emphasis on eyewitness seeing (<em>hoi ophthalmoi mou eidon</em> = my eyes have seen) echoes Isa 52:10 ("all the ends of the earth will see the salvation of our God") and the general biblical theme of the eyes of faith seeing what was promised. Simeon is the fulfillment-witness: the one who confirms that the long-promised salvation has arrived.</p>',
    "31": '<p>"Which you have prepared in the sight of all nations" (<em>ho hētoimasas kata prosōpon pantōn tōn laōn</em>) — the phrase echoes the preparation language of Isa 40:3 (prepare the way of the Lord) and extends the scope beyond Israel to "all the peoples" (<em>pantōn tōn laōn</em>). In Second Temple Judaism, most expressions of eschatological hope centered on the restoration of Israel, with the nations playing a secondary role (bringing gifts to Zion, being subdued, or becoming subordinate proselytes). Luke\'s infancy narrative consistently pushes toward universal inclusion, anticipating the Acts mission to the Gentiles.</p>',
    "32": '<p>"A light for revelation to the Gentiles and glory of your people Israel" (<em>phōs eis apokalypsin ethnōn kai doxan laou sou Israēl</em>) echoes Isa 42:6 ("I will make you a light for the Gentiles") and 49:6 ("I will make you a light for the Gentiles, that my salvation may reach to the ends of the earth"). The order — Gentiles first, then Israel — reverses the priority that ethnic Israelites might expect. The two groups are both included but in a grammatically parallel structure: the salvation is <em>both</em> "light of revelation to Gentiles" <em>and</em> "glory of your people Israel." This dual formulation is the programmatic statement of Luke-Acts\' inclusive mission (cf. Acts 1:8; 13:47; 28:28).</p>',
    "33": '<p>"The child\'s father and mother marveled" (<em>ethaumazon</em> — imperfect, repeated amazement) — Luke uses <em>ho patēr autou kai hē mētēr</em> (his father and his mother) rather than "Joseph and Mary," which some scribes found theologically awkward and modified. The marveling is not disbelief but the ongoing response to divine speech that exceeds comprehension. Even those who have received prior announcements (Mary at the annunciation, Joseph through an angel in Matthew) continue to be astonished by new dimensions of the revelation. This is Luke\'s portrait of faithful reception: reverent astonishment rather than casual familiarity with the divine.</p>',
    "34": '<p>Simeon\'s blessing turns from doxology to oracle. "This child is destined for the falling and rising of many in Israel" (<em>keitai eis ptōsin kai anastasin pollōn en tō Israēl</em>) — the paradox of Messiah as both cause of falling and cause of rising. In Second Temple messianic thinking, the Messiah would vindicate the righteous and judge the wicked; Simeon frames this judgment as <em>keitai</em> (is set/appointed — the destiny verb) for simultaneous falling and rising. The "sign spoken against" (<em>sēmeion antilegomenon</em>) anticipates the rejection-pattern of Luke-Acts (Acts 28:22 uses <em>antilegō</em> for the opposition to the Christian "sect").</p>',
    "35": '<p>"A sword will pierce your own soul" (<em>kai sou de autēs tēn psychēn dieleusetai rhomphaia</em>) — the <em>rhomphaia</em> (large broadsword — LXX word for the sword of divine judgment; Ps 22:20 LXX; Rev 1:16; 2:12; not the short <em>machaira</em>) indicates sharp penetrating pain, not a literal sword. Mary has just received the promise that her son is the world\'s savior; now she receives the counter-word that his mission will be her anguish. Simeon\'s oracle addresses her directly (<em>kai sou</em> = and yours) — the mother who bore the Messiah will not be exempt from the pain of the division he causes. "So that the thoughts of many hearts will be revealed" (<em>hopōs an apokaluphthōsin ek pollōn kardiōn dialogismoi</em>) — the Messiah functions as a revealer of the inner character that responses to him expose.</p>',
    "36": '<p>Anna (<em>Hanna</em> — Hebrew <em>ḥannāh</em> = grace/favor, the same name as the mother of Samuel) is identified with extraordinary genealogical precision: daughter of Penuel, tribe of Asher. The tribe of Asher was one of the "ten lost tribes" — the northern tribes dispersed by the Assyrians in 722 BCE — but Luke identifies a woman who still knew her Asherite genealogy, suggesting that tribal identity records were maintained even for the diaspora northern tribes. The prophetess (<em>prophētis</em>) title places her in the line of OT female prophets: Miriam (Exod 15:20), Deborah (Judg 4:4), Huldah (2 Kgs 22:14), and Noadiah (Neh 6:14). Female prophets in Second Temple Judaism are attested in texts like the Sibylline Oracles.</p>',
    "37": '<p>Anna\'s biography: married seven years after her betrothal, then widowed for eighty-four years (or at eighty-four years old — the Greek is ambiguous: <em>heōs etōn ogdoēkonta tessarōn</em> could mean either). If she was widowed after seven years of marriage and then lived 84 more years, she would be over one hundred. If she was now 84, she was widowed as a young woman. Either way, her life is defined by extraordinary fidelity: "she never left the temple but worshipped night and day with fasting and prayer." This total devotion to temple prayer echoes the Essene piety of continual prayer found in the Dead Sea Scrolls, and anticipates Luke\'s emphasis on persistent prayer throughout the Gospel (11:1-13; 18:1-8; 21:36; 22:40-46).</p>',
    "38": '<p>Anna "came up at that very moment" (<em>autē tē hōra</em> = at that hour, at exactly that moment) — the divine timing of her appearance alongside Simeon\'s is Luke\'s signal that both encounters are orchestrated. She "gave thanks to God" (<em>anthhomologeito tō theō</em> = gave thanks publicly to God; the compound with <em>anti-</em> suggests responsive praise, thanksgiving offered back to God). She "spoke about the child to all who were looking forward to the redemption of Jerusalem" (<em>lytrōsin Ierousalēm</em> = the ransoming/redemption of Jerusalem — a specifically Zion-focused eschatological hope; contrast Elizabeth\'s Magnificat-world of the poor and Simeon\'s all-nations light). Anna represents the Jerusalem-centered hope; her audience is those who share this waiting posture.</p>',
    "39": '<p>The family\'s return to Galilee "after completing everything required by the Law" (<em>hōs etelesan panta ta kata ton nomon Kyriou</em>) frames the entire Jerusalem episode as Torah fulfillment. Luke\'s infancy narrative is saturated with Torah-observance notices (circumcision: v.21; purification: v.22-24; presentation: v.22-23; Passover: v.41). The return to Nazareth establishes the family\'s home base before the next Jerusalem episode (vv.41-52). Luke omits the flight to Egypt (Matthew 2:13-18) and Herod\'s massacre of the infants; his account moves directly from the presentation to the childhood summary at v.40.</p>',
    "40": '<p>"The child grew and became strong, filled with wisdom, and the grace of God was on him" — the childhood summary formula echoes the summary of Samuel\'s growth (1 Sam 2:21, 26) and John the Baptist\'s growth (Luke 1:80: "the child grew and became strong in spirit"). Ancient biographical convention included brief summaries of childhood development that established the future great person\'s character formation. The four elements — growth, strength, wisdom, divine favor — are the ideal qualities of the biblical hero. <em>Sophia</em> (wisdom) and <em>charis theou</em> (grace/favor of God) are Lukan emphases throughout: wisdom is both intellectual and practical insight, and divine favor is the relational standing with God that enables mission.</p>',
    "41": '<p>The annual Jerusalem Passover pilgrimage was one of three obligatory pilgrimage festivals (<em>šālôš rĕgālîm</em>): Passover, Weeks/Pentecost, and Tabernacles (Exod 23:14-17; Deut 16:1-17). Jewish law required adult males to appear in Jerusalem three times a year, but in practice many diaspora Jews attended only Passover. Galilean pilgrims traveled in large caravans for safety on the three-to-four-day journey; Josephus describes Galilean pilgrims as particularly frequent targets of Samaritan hostility when they traveled through Samaria (<em>Jewish Antiquities</em> 20.118-136). Luke says the family went "every year" (<em>kat etos</em>), indicating ongoing faithful observance rather than occasional compliance.</p>',
    "42": '<p>At twelve years old (<em>etōn dōdeka</em>), a Jewish boy was approaching but had not yet reached his formal religious majority. The rabbinic institution of Bar Mitzvah as we know it developed in the medieval period, but the age of thirteen was recognized in Second Temple Judaism as the age of responsibility for Torah commandments (m. <em>Avot</em> 5:21: "at thirteen, responsible for the commandments"). At twelve, a boy would be in the preparatory period — old enough to participate seriously in the Passover discussions, learning from his father and other teachers. Luke\'s choice of twelve as the age of the temple episode is likely deliberate: Jesus is on the threshold of religious majority, demonstrating precocious mastery that will soon be formally recognized.</p>',
    "43": '<p>The conclusion of the festival and the family\'s return-journey separation from Jesus reflects the communal caravan travel culture: large groups of families from the same region traveled together, and children moved freely within the extended group. The assumption that Jesus was "in the company" (<em>en tē synodia</em> = in the travel-group — a specific word for a traveling company/caravan) reflects the practical reality of Galilean pilgrimage: you did not keep constant visual track of children in a large group of known families. The realization that he was not present would have come when the group camped for the night and children returned to their families.</p>',
    "44": '<p>The search "among their relatives and friends" (<em>en tois syngeneusin kai tois gnōstois</em>) reflects the kinship-based social structure of first-century Palestinian villages. Nazareth was a small community; the entire Galilean contingent on the pilgrimage likely included most of the village and surrounding area. Everyone would have known everyone else. The fact that a full day of travel passed before the parents realized Jesus was not in the group suggests either the size of the caravan or the normalcy of children moving between family units. The return to Jerusalem (a day\'s travel back) adds urgency: the festival crowds were dispersing.</p>',
    "45": '<p>The three-day search (<em>meta hēmeras treis heuron auton</em> = after three days they found him — but see v.46 which specifies "in the temple courts"; the "three days" likely counts the day of leaving, the day of returning, and the day of finding) and the finding in the temple create a narrative that anticipates the passion-resurrection pattern: absence followed by finding after three days. Luke may intend this temporal echo deliberately, as the boy\'s temple self-identification as being in "his Father\'s house" (v.49) anticipates the resurrection\'s reconfirmation of his divine Sonship.</p>',
    "46": '<p>Jesus is found "sitting among the teachers, listening and asking questions" (<em>kathezomenon en mesō tōn didaskalōn kai akouonta autōn kai eperōtōnta autous</em>) — the pedagogical posture is standard rabbinic learning: the student sits at the teacher\'s feet (cf. Paul "brought up at the feet of Gamaliel," Acts 22:3), listens, and asks questions. Rabbinic learning was dialectical — not lecturing but question-and-answer, probing arguments, considering multiple opinions. The <em>didaskaloi</em> (teachers) in the temple courts during Passover would have been prominent sages who used the festival season for public instruction. The twelve-year-old Jesus is participating in this elite intellectual conversation, not merely observing.</p>',
    "47": '<p>The amazement of those who heard (<em>existanto de pantes hoi akouontes autou epi tē synesei kai tais apokrisesin autou</em>) — <em>synesis</em> (understanding, comprehension — the synthetic intelligence that grasps connections; cf. Dan 1:4, 17 LXX for the wisdom of Daniel and his companions) and <em>apokrisesin</em> (answers — implying that Jesus was not only asking questions but giving answers). In a question-and-answer learning session, the student\'s answers reveal the quality of his understanding; Jesus\'s answers astonish professionals. This scene is Luke\'s only window into Jesus\'s childhood development; it functions as a preview of the authoritative teaching that will characterize his adult ministry.</p>',
    "48": '<p>Mary\'s rebuke ("Son, why have you treated us this way?") follows the normal parental anxiety pattern; the formal address <em>teknon</em> (child) signals a mixture of relief and reproach. Her statement "your father and I have been anxiously searching" (<em>ho patēr sou kagō odynōmenoi ezētoumen se</em>) uses <em>odynaomai</em> (be in anguish, suffer pain — also 16:24, 25 for the rich man\'s torment in Hades; Acts 20:38 for the elders grieving over Paul\'s departure): the word describes acute emotional pain. The reference to Joseph as "your father" will be answered by Jesus\'s counter-reference to "my Father" (v.49) — the implicit tension between earthly and heavenly paternity that underlies the entire infancy narrative.</p>',
    "49": '<p>Jesus\'s first recorded words: "Did you not know that I must be in my Father\'s house?" (<em>ouk ēdeite hoti en tois tou patros mou dei einai me</em>). The <em>dei</em> (must, it is necessary) is the divine-necessity word used throughout Luke-Acts for the events of the divine plan (9:22; 13:33; 22:37; 24:7, 26, 44; Acts 1:16; 3:21). The phrase <em>en tois tou patros mou</em> is ambiguous in Greek: it can mean "in the things/affairs of my Father" (his Father\'s business, the NIV margin) or "in the house of my Father" (the temple, NIV main text). The temple as God\'s house is clear from Ps 27:4; 122:1, 9. The divine Sonship claim is unmistakable: not "our Father" (as in the Lord\'s Prayer) but "my Father" — a relationship of unique intimacy.</p>',
    "50": '<p>"They did not understand what he said to them" (<em>kai autoi ou synēkan to rēma ho elalēsen autois</em>) — the non-understanding of the parents, even after the annunciation and the Simeon/Anna encounters, is Luke\'s pattern of preserved mystery. The same pattern appears at 9:45 and 18:34 for the disciples\' non-understanding of passion predictions. Luke presents the full meaning of Jesus\'s identity and mission as something that can only be grasped progressively; even those closest to him cannot comprehend the whole while events are unfolding. This is not a failure of faith but a feature of prophetic revelation: its full meaning is visible only in retrospect.</p>',
    "51": '<p>"He went down to Nazareth with them and was obedient to them" (<em>katebē met autōn kai ēlthen eis Nazareth kai ēn hupotassomenos autois</em>) — the descent from Jerusalem (which is always "up" and Nazareth is always "down" in Luke — geographical reality reflecting theological symbolism) signals voluntary return to the subordinate position. <em>Hupotassomenos</em> (obedient, subject — present participle of <em>hypotassō</em> = subordinate, place under authority) is the self-subordination word; Paul uses it for wives, children, and slaves in household codes (Eph 5:22; 6:1, 5; Col 3:18, 20), and for Christ\'s ultimate subordination to the Father (1 Cor 15:28). The one who has just demonstrated divine Sonship voluntarily returns to human family subordination — an enacted kenosis.</p>',
    "52": '<p>"Jesus grew in wisdom and stature and in favor with God and man" (<em>Iēsous proekopten sophia kai hēlikia kai chariti para theō kai anthrōpois</em>) — this closing summary of the childhood echoes 1 Sam 2:26 (Samuel: "the boy Samuel grew in stature and in favor with the LORD and with people") and Prov 3:4 ("find favor and a good name in the sight of God and man"). <em>Proekopten</em> (advanced, progressed — from <em>prokoptō</em> = strike forward, make progress; the word for advancing in a craft or discipline; also Gal 1:14 for Paul\'s advancement in Judaism) indicates genuine developmental growth, not merely ceremonial increases. Luke presents Jesus\'s human development as authentic: growing in wisdom, physical maturity (<em>hēlikia</em> = stature or age), and relational standing with both God and humans.</p>'
  },
  "3": {
    "1": '<p>Luke\'s dating formula for John the Baptist\'s ministry is the most elaborate of any NT Gospel and reflects Greco-Roman historiographical convention (cf. Thucydides\' synchronism of the Peloponnesian War\'s start with multiple rulers; Josephus\'s similar datings). The fifteenth year of Tiberius Caesar (who became emperor in 14 CE) = 28-29 CE (or 27-28 CE if counted from his co-regency with Augustus in 12-13 CE). Pontius Pilate was governor (<em>hēgemōn</em>) of Judea 26-36 CE. Herod Antipas was tetrarch of Galilee and Perea 4 BCE–39 CE (the son of Herod the Great who executed John the Baptist). Philip was tetrarch of Iturea and Trachonitis 4 BCE–34 CE. Lysanias of Abilene is attested epigraphically from inscriptions near Damascus. The six-ruler synchronism anchors the story in world history: this is not mythology but dateable events in a specific political context.</p>',
    "2": '<p>The "high priesthood of Annas and Caiaphas" reflects a complex political situation. Annas (Hebrew <em>Ḥananyāh</em>) served as high priest 6–15 CE before being deposed by Rome (only the Roman governor could depose high priests, which was itself a violation of Jewish law that held the position was for life). His son-in-law Caiaphas served 18–36 CE as the actual functioning high priest. But Annas retained enormous informal authority; John 18:13 notes that Jesus was first brought to Annas. Five of Annas\'s sons also served as high priests. The family effectively controlled the high priesthood for decades, making "Annas and Caiaphas" a joint description of the priestly power structure. The word of God coming to John in the wilderness rather than to the high priestly establishment is a prophetic challenge to institutional religion.</p>',
    "3": '<p>John\'s <em>baptisma metanoias eis aphesin hamartiōn</em> (baptism of repentance for forgiveness of sins) had Jewish antecedents but was distinctive. Jewish ritual immersion (<em>mikveh</em>) was self-administered for purification from specific ritual impurities; John\'s baptism was administered by John himself to others (a one-time act, not repeated purification), associated with repentance and preparation for divine judgment, and open to all (including those of Jewish birth who would normally not need conversion immersion). The Qumran community also practiced immersion for moral purification, but required members to be already repentant before immersing. John reversed this: the immersion was performed once as the public seal of repentance. His location "in all the country around the Jordan" (the wilderness east of the Jordan) placed him in the geography of the Exodus — Israel prepared to enter the land again.</p>',
    "4": '<p>The Isaiah citation (Isa 40:3-5) in Luke is the longest of the three Synoptic accounts — Luke adds vv.5-6 (the valleys-filled, mountains-made-low, all-flesh-will-see material) while Matthew and Mark quote only v.3. The citation from the LXX identifies John\'s wilderness ministry as the fulfillment of the "voice in the wilderness" that prepares the Lord\'s way. In Isa 40, the original context is the end of Babylonian exile — a new Exodus of Israel from captivity. Luke\'s use places John as the one who prepares the new Exodus that Jesus will accomplish (9:31: Moses and Elijah speak of Jesus\'s <em>exodon</em> = departure/exodus at Jerusalem). The road-building metaphor (making straight the crooked, filling valleys, leveling mountains) images comprehensive divine action that overcomes all obstacles to the divine advance.</p>',
    "5": '<p>The continuation of the Isaiah citation (absent from Matthew and Mark) emphasizes the geographical comprehensiveness of preparation: "every valley shall be filled in, every mountain and hill made low, the crooked shall become straight, the rough smooth." In ancient Near Eastern royal ideology, when a great king traveled through his realm, roads were prepared — corvée labor filled holes, leveled obstacles, straightened paths. The cosmic road-preparation metaphor images the entire created order being prepared for the divine visitation. The phrase "all flesh will see God\'s salvation" (v.6) is the universal-scope element that Luke emphasizes, anticipating Acts\' mission to all nations.</p>',
    "6": '<p>"All flesh will see God\'s salvation" (<em>kai opsetai pasa sarx to sōtērion tou theou</em> — Isa 40:5 LXX) — this final line of Luke\'s Isaiah citation provides the theological rationale for the whole citation. The scope is universal (<em>pasa sarx</em> = all flesh, every human being) rather than Israel-only. Luke\'s inclusion of this verse (absent from Matthew and Mark) signals his programmatic universalism: the mission of John and Jesus is not for Israel alone but for all humanity. This verse anticipates Simeon\'s "all nations" (2:31) and Jesus\'s "all people" (3:10) and the Acts mission to "the ends of the earth" (Acts 1:8).</p>',
    "7": '<p>John\'s opening address to "the crowds coming to be baptized" — calling them "brood of vipers" (<em>gennēmata echidnōn</em> = offspring of vipers; the same address in Matthew is directed specifically to Pharisees and Sadducees) — reflects the prophetic tradition of direct confrontation with the audience. In prophetic literature (Isaiah, Jeremiah, Amos, Ezekiel) the prophet addresses the people as a whole with harsh characterizations that expose the gap between their self-understanding and divine assessment. John asks: "Who warned you to flee from the coming wrath?" (<em>tis hypedeixen hymin phygein apo tēs mellousēs orgēs</em>) — implying that their baptism-seeking is motivated by fear of judgment rather than genuine repentance.</p>',
    "8": '<p>"Do not begin to say to yourselves, \'We have Abraham as our father\'" — this strikes at the central ethnic-religious confidence of Second Temple Judaism. Abrahamic descent was understood as providing covenant standing and divine protection. The Rabbis debated whether all Israel had a share in the world to come (m. <em>Sanhedrin</em> 10.1); the default assumption was that Abrahamic birth was salvifically significant. John challenges this ethnic-biological confidence with the missionary claim: "God is able from these stones to raise up children for Abraham." The wordplay may be Aramaic: <em>abnayya</em> (children) and <em>abnayya</em> (stones). The judgment (<em>orgē</em> = wrath) is coming regardless of genealogy; only transformed conduct constitutes genuine repentance.</p>',
    "9": '<p>The axe-at-the-root image (<em>hē axinē pros tēn rhizan tōn dendrōn keitai</em> = the axe is already laid at the root of the trees) indicates that the judgment is not merely coming but imminent — the axe is positioned and ready. In prophetic imagery, the destruction of a tree represents the end of a dynasty or nation (Isa 10:34; Jer 11:19; Ezek 31:3-14; Dan 4:14). The criterion for judgment is fruitfulness (<em>karpos axion tēs metanoias</em> = fruit worthy of repentance, v.8; <em>karpon kalon</em> = good fruit, v.9) — not genealogy, not religious affiliation, not temple proximity. Trees that fail to produce are cut down and thrown into fire; the fire imagery connects to the coming judgment John describes in v.17.</p>',
    "10": '<p>The crowd\'s response — "What should we do then?" (<em>ti oun poiēsōmen</em>) — is the appropriate response to John\'s challenge: not theological debate but practical inquiry about conduct. This question (also from tax collectors in v.12 and soldiers in v.14) reflects the Jewish tradition of asking the rabbi for halakic guidance: "What is the ruling? How should I act?" The social location of the questioners broadens through these three groups: crowds (the general public), tax collectors (collaborators with Roman revenue system), and soldiers (presumably Herod\'s troops, possibly with Roman auxiliaries). John\'s ethical teaching to all three is practical and social rather than cultic.</p>',
    "11": '<p>John\'s answer to the crowd (<em>ho echōn duo chitōnas metadotō tō mē echonti</em> = the one having two tunics let him share with the one who has none) addresses economic inequality directly. The <em>chitōn</em> (undergarment/tunic — the basic garment worn next to the skin; distinct from the outer <em>himation</em>) was a fundamental necessity; having two while another has none is a basic inequity that John identifies as the "fruit worthy of repentance." This is ethical radicalism without the temple-cult framing: the demonstration of repentance is sharing material goods. The food-sharing addition (<em>kai ho echōn brōmata homoiōs poieitō</em> = and the one having food let him do likewise) extends the principle to all material necessities.</p>',
    "12": '<p>Tax collectors (<em>telōnai</em>) who came to be baptized represent one of the most striking elements of John\'s ministry. The <em>telōnai</em> system in Roman Palestine worked through <em>publicani</em> (tax-farm contractors) who bought the right to collect taxes in a region and then employed local subcontractors (<em>telōnai</em>) to collect from individuals. The subcontractors were typically Jewish men who collected Roman taxes from their own people, taking their profit by collecting more than the official assessment. They were therefore both collaborators with Roman occupation and exploiters of their neighbors — doubly despised. Their approaching John acknowledges their moral situation. Their question "Teacher, what should we do?" uses <em>didaskalos</em> (teacher) for John — a respectful address that acknowledges his authority.</p>',
    "13": '<p>John\'s instruction to tax collectors — "Don\'t collect more than you are required to" (<em>mēden pleon para to diatetagmenon hymin prassete</em>) — does not require them to quit their profession but to practice it honestly. This is remarkably moderate for prophetic ethics: John does not condemn the entire tax system or demand withdrawal from collaboration. The practical issue was the surcharge: the official tax rate was fixed, but collectors profited by demanding more and pocketing the difference. John\'s instruction addresses the specific moral failure (extortion/overcharging) without mandating structural revolution. This pattern — addressing the specific moral failure within a person\'s actual social location — runs through John\'s three ethical responses (vv.11, 13, 14).</p>',
    "14": '<p>Soldiers (<em>strateuomenoi</em> = those serving as soldiers; the present participle indicates active military service) also came to John. These were likely Herod Antipas\'s troops (Roman legionary soldiers would not typically have sought out a Jewish prophet), though some Roman auxiliaries were Jewish. John\'s response addresses two specific military abuses: <em>mē diaseiēte mēde sykophantēsēte</em> (do not extort by violence and do not falsely accuse people — <em>diaseiō</em> = shake thoroughly, violently extort; <em>sykophantō</em> = make false accusations for personal gain) and <em>arkeisthe tois opsōniois hymōn</em> (be content with your pay — <em>opsōnion</em> = soldier\'s pay/ration-money). Both abuses — violent shakedowns and false accusations leading to fines — were endemic in military occupation contexts throughout the ancient world.</p>',
    "15": '<p>The widespread messianic expectation (<em>prosdokōntos tou laou kai dialogizomenōn pantōn en tais kardiais autōn peri tou Iōannou, mēpote autos eiē ho Christos</em> = the people were in expectation and all were reasoning in their hearts about John, whether he might be the Messiah) reflects a documented feature of Second Temple Judaism: intense eschatological expectation, particularly in the 1st century CE. Josephus describes multiple messianic movements: Theudas, the Egyptian prophet, Simon of Peraea, Athronges (<em>Jewish Antiquities</em> 17-20). The Dead Sea Scrolls document expectation of multiple messianic figures (a priestly messiah and a royal messiah). The population was primed for messianic arrival; John\'s unusual location, practice, and preaching made him a natural candidate.</p>',
    "16": '<p>John\'s self-differentiation from the Coming One uses the sandal-strap imagery: "the straps of whose sandals I am not worthy to untie." Rabbinic tradition held that a disciple could perform any service for his teacher that a slave performed for a master, except untying sandals (b. <em>Ketubot</em> 96a). Untying sandals was a slave\'s task; even a disciple did not do this. John places himself below the level of the Coming One\'s disciple. The contrast of baptisms — water (<em>en hydati</em>) vs. Holy Spirit and fire (<em>en pneumati hagiō kai pyri</em>) — identifies John\'s baptism as preparatory, the external symbol of internal repentance, while the Coming One\'s baptism will be the transforming reality: divine Spirit and purifying fire. "Fire" here connects to both purification imagery (Mal 3:2-3) and judgment imagery (v.17).</p>',
    "17": '<p>The winnowing fork (<em>ptyon</em>) image comes from Palestinian agricultural practice: after threshing (beating the grain to separate kernels from stalks), the grain was thrown into the air with a winnowing fork to allow the wind to carry away the lighter chaff (<em>achuron</em>) while the heavier grain (<em>siton</em> = wheat) fell to the threshing floor. The Coming One holds the winnowing fork over his threshing floor — the entire world is the floor, the process is separation, the result is storage for the wheat and fire for the chaff. "Unquenchable fire" (<em>puri asbEstō</em>) echoes Isa 66:24 (the final vision of judgment) and Jer 7:20. The agricultural metaphor makes the judgment process concrete and understandable to an agrarian audience.</p>',
    "18": '<p>"With many other words John exhorted the people and proclaimed the good news" (<em>polla men oun kai hetera parakalōn euēngelizeto ton laon</em>) — Luke summarizes John\'s extensive ministry with two verbs: <em>parakaleō</em> (exhort, encourage — the Paraclete verb; strong urging toward specific action) and <em>euangelizō</em> (proclaim good news — the gospel-proclamation verb applied here to John\'s preaching). Luke\'s use of <em>euangelizō</em> for John\'s preaching (unique among the Synoptics) suggests that John\'s proclamation was already part of the good-news announcement of the kingdom, not merely preparation. The summary signals that vv.10-14 are selective examples, not a complete account.</p>',
    "19": '<p>Herod Antipas\'s marriage to Herodias was politically and morally complicated. Herodias was the daughter of Aristobulus, son of Herod the Great (thus Herod Antipas\'s niece) and had been married to Herod Philip I (a half-brother of Antipas, not the Philip of v.1), a private citizen living in Rome. Herod Antipas visited Rome, became enamored of Herodias, and they agreed to marry — which required Antipas to divorce his first wife (the daughter of the Nabataean king Aretas IV, whose resulting anger eventually led to military conflict: Josephus, <em>Antiquities</em> 18.5.1). Jewish law (Lev 18:16; 20:21) prohibited marrying a brother\'s wife during the brother\'s lifetime. John\'s public rebuke of this marriage was both prophetically bold and politically dangerous.</p>',
    "20": '<p>John\'s imprisonment by Herod Antipas is placed by Luke before the account of Jesus\'s baptism (a characteristic Lukan device of closure: "finishing" John\'s story before beginning Jesus\'s). Josephus provides corroborating detail (<em>Antiquities</em> 18.5.2): Herod imprisoned John at Machaerus (a fortress east of the Dead Sea) because he feared John\'s influence over the people might lead to a revolt. Luke attributes the imprisonment to John\'s rebuke of Herod\'s marriage; both accounts can be true. The phrase "Herod added this to them all" (<em>prosethēken kai touto epi pasin</em>) — adding imprisonment to his other evils — is a Lukan editorial comment that frames Herod as the accumulator of wickedness; the same accumulation pattern characterizes Jerusalem\'s leadership in the passion narrative.</p>',
    "21": '<p>The setting of Jesus\'s baptism — "when all the people were being baptized" (<em>en tō baptisthēnai hapanta ton laon</em>) — places Jesus\'s baptism within the mass movement of John\'s ministry, not as an isolated event. The genitive absolute frame (<em>Iēsou baptisthentos kai proseuchomenou</em> = Jesus having been baptized and while he was praying) is Luke\'s characteristic prayer-notice at major revelatory moments: the heavenly disclosure comes not at the baptism but during the subsequent prayer. Luke is the only Gospel to mention prayer at the baptism, consistent with his prayer-emphasis throughout (3:21; 6:12; 9:18, 28-29; 11:1; 22:41-45). The heavens "were opened" (<em>aneōgen ton ouranon</em>) signals the end of prophetic silence and the beginning of a new era of divine communication.</p>',
    "22": '<p>The Holy Spirit descends "in bodily form like a dove" (<em>sōmatikō eidei hōs peristeran</em>) — Luke\'s "bodily form" is unique to his account; the other Gospels say "as a dove" without the "bodily form" qualifier. The dove had multiple symbolic resonances: (1) Gen 8:8-12, where the dove signals the end of the flood and the beginning of new creation; (2) the divine presence hovering (<em>merachephet</em>) over the waters at creation (Gen 1:2), with rabbinic tradition comparing the Spirit\'s movement to a dove hovering; (3) Song of Songs 2:14 and 5:2 where the beloved is called "my dove." The voice from heaven (<em>phōnē ek tou ouranou</em>) combines Ps 2:7 ("You are my Son, today I have begotten you") and Isa 42:1 ("my chosen one in whom my soul delights"), designating Jesus as both Davidic king and Servant.</p>',
    "23": '<p>"Jesus himself was about thirty years old when he began" (<em>Iēsous... ēn archomenos hōsei etōn triakonta</em>) — the "about" (<em>hōsei</em>) softens the number; thirty was the age for Levitical priestly service (Num 4:3, 23, 30, 35, 39, 43, 47) and the age at which David became king (2 Sam 5:4). Luke may be invoking these precedents. The genealogy ("as was thought, the son of Joseph" — <em>nomizomenōn huios Iōsēph</em> = of him being considered the son of Joseph; the parenthetical qualification preserves the virgin birth) runs in reverse order from Jesus back to God, the opposite direction of Matthew\'s forward-running genealogy from Abraham to Jesus. Luke\'s reverse structure emphasizes origin rather than goal.</p>',
    "24": '<p>The genealogy from Joseph back to Heli (v.23) and through Matthat, Levi, Melchi, Jannai, Joseph (v.24) covers the immediate post-exilic period. Luke\'s genealogy diverges from Matthew\'s at David: Luke goes through Nathan (David\'s son by Bathsheba, 2 Sam 5:14; 1 Chr 3:5), while Matthew goes through Solomon. This means Luke\'s genealogy traces a non-royal line of Davidic descent — the "Nathan line" rather than the "Solomon-royal line." Various explanations have been offered: (1) Luke traces Mary\'s genealogy through Joseph (a levirate marriage scenario); (2) Luke traces Joseph\'s biological lineage while Matthew traces legal/adopted lineage; (3) both are variants of the same general Davidic descent. The key point is Davidic ancestry regardless of the specific line.</p>',
    "25": '<p>The names Mattathias, Amos, Nahum, Esli, Naggai cover the inter-testamental period between the Babylonian exile (ca. 586 BCE) and the Maccabean period (164 BCE). Most of these names are not attested in canonical OT genealogies; they represent oral or documentary tradition preserved outside canonical texts. The appearance of "Amos" and "Nahum" (both OT prophet names) in the genealogical list does not mean the prophets themselves are in view; these were common names in Jewish practice, particularly names of prestigious ancestors being honored by reuse.</p>',
    "26": '<p>Maath, Mattathias, Semein, Josech, Joda represent figures in the post-exilic period through the Persian era. The density of Mattathias-names in the Lukan genealogy (vv.25, 26) reflects the popularity of this name in the Maccabean period (Mattathias was the father of the Maccabean revolt). The Semein variant may correspond to the Shimei of OT records. The genealogical density here — multiple generations compressed into brief name-lists — reflects the actual state of preserved ancestral records for non-royal families in Second Temple Judaism: fragmentary, often relying on oral tradition for the generations between major recorded figures.</p>',
    "27": '<p>Joanan, Rhesa, Zerubbabel, Shealtiel, Neri — here Luke\'s genealogy reconnects with the canonical OT. Zerubbabel (son of Shealtiel) is the figure who led the first return from Babylonian exile (Ezra 2:2; Hag 1:1; Zech 4:6-10) and was of the Davidic line (1 Chr 3:17-19). Luke traces Zerubbabel\'s ancestry through Neri rather than through Jehoiachin/Jechoniah (which Matthew uses): this is either a different Zerubbabel or Luke tracks his ancestry through a different ancestral line than Matthew (the Neri line vs. the Jehoiachin line). Zerubbabel represents the hope of Davidic restoration — the expectation that after the exile, a Davidic ruler would reestablish the kingdom. Jesus is the fulfillment of that hope.</p>',
    "28": '<p>Melchi, Addi, Cosam, Elmadam, Er — these names cover the early post-exilic Persian period, generations between the return under Zerubbabel (ca. 537 BCE) and the later Persian period. None of these names appear in canonical OT genealogical lists, indicating they come from non-canonical ancestral records. The preservation of such detailed ancestral information across multiple generations reflects the importance of genealogical memory in Jewish culture: priestly families needed genealogies for temple service eligibility, and Davidic families maintained their lineage records against the day of messianic restoration.</p>',
    "29": '<p>Joshua, Eliezer, Jorim, Matthat, Levi — these names cover the period from approximately 450-350 BCE (late Persian period). The name Joshua (<em>Iēsous</em> in Greek) reappears in the genealogy; the multiple Josephs and Levis also reflect the recycling of ancestral honorific names. These generations bridge the "silent" intertestamental period when canonical records become sparse. Luke\'s genealogy fills in these generations with names that the traditional genealogical memory preserved, whether through temple archives (Josephus says genealogical records were kept in the Jerusalem temple: <em>Against Apion</em> 1.7) or family oral tradition.</p>',
    "30": '<p>Simeon, Judah, Joseph, Jonam, Eliakim — further back into the exilic period (ca. 550-500 BCE). The names Simeon, Judah, and Joseph are patriarchal names being reused honorifically. The appearance of "Judah" in this list reflects the tribal identity of the Davidic line (Gen 49:10: "the scepter will not depart from Judah"). Luke\'s genealogy through Nathan rather than Solomon follows a secondary Davidic line; this secondary line was apparently remembered and preserved alongside the primary royal line. Both lines are genuinely Davidic, establishing the genealogical claim regardless of which line one follows.</p>',
    "31": '<p>Melea, Menna, Mattatha, Nathan, David — the genealogy reaches David through the Nathan line. Nathan (<em>Natan</em>) was David\'s third son by Bathsheba (after Shimea and Shammua; 1 Chr 3:5) and is mentioned in Zech 12:12 as a distinct Davidic branch mourning for the pierced one. The Nathan line diverges from Matthew\'s Solomon line at this exact point. Both genealogies agree on David as the ancestor; they simply follow different descendants. Luke\'s choice of the Nathan line may reflect an independent genealogical tradition for Mary\'s ancestry (if Luke traces Mary through Joseph by legal adoption or levirate convention).</p>',
    "32": '<p>Jesse, Obed, Boaz, Sala (Salmon), Nahshon — Luke\'s genealogy agrees with Matthew\'s at this point and with the canonical genealogy of Ruth 4:18-22 and 1 Chr 2:4-15. Boaz is the kinsman-redeemer of Ruth, whose Gentile inclusion (a Moabitess) in the Davidic lineage is a precedent for Luke\'s universal scope. Nahshon was the leader of the tribe of Judah during the wilderness period (Num 1:7; 2:3; 7:12) and a prominent ancestor. The agreement between Luke and Matthew at these names confirms both genealogies draw on the same canonical tradition for this pre-monarchic period.</p>',
    "33": '<p>Amminadab, Ram (Admin in some manuscripts), Hezron, Perez, Judah — these patriarchal period ancestors bring the lineage back toward the twelve tribes. Perez (Hebrew <em>Pereẓ</em>) was one of the twin sons of Judah and Tamar (Gen 38:29) and is listed in the genealogy of David in Ruth 4:18. The Perez-line is the line through which the Davidic promise ran. The slight variations between Luke\'s spelling and Matthew\'s (Ram vs. Admin) reflect textual transmission variants in the Greek manuscript tradition of these rare names from Hebrew genealogies.</p>',
    "34": '<p>Jacob, Isaac, Abraham, Terah, Nahor — the genealogy enters the patriarchal narrative, with the three Abrahamic ancestors (Abraham, Isaac, Jacob) who are the founding figures of covenant Israel. Abraham\'s inclusion signals that Jesus\'s ancestry goes to the beginning of the covenant people; Terah and Nahor take the lineage back into the pre-Abrahamic Mesopotamian world (Gen 11:24-27). Luke\'s genealogy going back to Adam (unlike Matthew\'s which stops at Abraham) signals the universal human scope of Jesus\'s identity: he is Messiah of Israel but also son of humanity.</p>',
    "35": '<p>Serug, Reu, Peleg, Eber, Shelah — these are the descendants of Shem listed in Gen 11:10-26, the "table of nations" section of Genesis. Peleg is notable as the one "in whose time the earth was divided" (<em>niphlegah</em>, Gen 10:25) — possibly the dispersion of Babel. Eber is the ancestor whose name (in some traditions) gave origin to the designation "Hebrew" (<em>ibrit</em>). These ancestors take the genealogy through the early post-flood era into the Shem-line that leads to Abraham. Luke\'s inclusion of these names demonstrates continuity with the entire biblical genealogical tradition from creation through Abraham to Jesus.</p>',
    "36": '<p>Cainan, Arphaxad, Shem, Noah, Lamech — notably, Luke includes "Cainan" between Arphaxad and Shelah, which follows the LXX (Septuagint) text of Gen 11:12-13 rather than the Hebrew Masoretic text (which lacks Cainan). The Masoretic text: Arphaxad begot Shelah. The LXX: Arphaxad begot Cainan, Cainan begot Shelah. This extra LXX generation creates a discrepancy between Luke\'s genealogy and the Hebrew canonical text that has puzzled interpreters for centuries. Luke uses the LXX throughout his writings; his genealogy here reflects the LXX\'s text of Genesis rather than an error or independent tradition. It signals that Luke\'s audience was primarily Greek-speaking and Scripture-reading through the LXX.</p>',
    "37": '<p>Methuselah (the longest-lived person in the OT, 969 years — Gen 5:27), Enoch (who "walked with God and was not, for God took him" — Gen 5:22-24; the figure whose non-death generated extensive Second Temple speculation about heavenly journeys and divine secrets, e.g., 1 Enoch, 2 Enoch, Jubilees), Jared, Mahalalel, Kenan — these are the antediluvian patriarchs of Gen 5, the pre-flood ancestors whose extraordinarily long lifespans mark the primeval era. Enoch\'s inclusion is significant: the most celebrated figure of pre-flood righteousness is in Jesus\'s genealogy, connecting Jesus\'s lineage to the tradition of those who "walked with God."</p>',
    "38": '<p>Enosh, Seth, Adam, and then "the son of God" (<em>tou theou</em>) — Luke\'s genealogy ends (or begins, moving forward) with "son of God." The final "son of God" designation is the climax of the reverse genealogy: tracing back through Abraham, Noah, Seth, and Adam, the ultimate origin of Jesus\'s humanity is in God himself. This conclusion connects to the divine voice at the baptism ("You are my Son" — v.22) and to the creation narrative (Adam was created directly by God, Gen 2:7, making him uniquely "of God"). The Lukan Christology here is both fully human (son of Adam) and fully divine (son of God) — the two affirmations frame his entire ministry. The genealogy\'s ending at "son of God" functions as the theological commentary on the baptismal voice.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'luke')
    merge_comm(existing, LUKE_CH2_3)
    save_comm('mkt-context', 'luke', existing)
    ch2 = len(existing.get('2', {}))
    ch3 = len(existing.get('3', {}))
    print(f'Luke 2: {ch2} verses, Luke 3: {ch3} verses.')

if __name__ == '__main__':
    main()
